import java.util.*;
import java.util.regex.*;

public class SimpleEliza {
    // ELIZA (1966) used pattern matching - no real understanding
    private static final Map<String, String> patterns = new LinkedHashMap<>();

    static {
        patterns.put(".*I am (.*)", "How long have you been %s?");
        patterns.put(".*I feel (.*)", "Why do you feel %s?");
        patterns.put(".*my mother (.*)", "Tell me more about your family.");
        patterns.put(".*my father (.*)", "How does that make you feel about your father?");
        patterns.put(".*yes.*", "You seem quite sure. Can you elaborate?");
        patterns.put(".*no.*", "Why not?");
        patterns.put(".*", "Please go on...");
    }

    public static String respond(String input) {
        input = input.toLowerCase();
        for (Map.Entry<String, String> entry : patterns.entrySet()) {
            Pattern p = Pattern.compile(entry.getKey(), Pattern.CASE_INSENSITIVE);
            Matcher m = p.matcher(input);
            if (m.matches()) {
                if (m.groupCount() > 0) {
                    return String.format(entry.getValue(), m.group(1));
                }
                return entry.getValue();
            }
        }
        return "Please continue...";
    }

    public static void main(String[] args) {
        System.out.println("ELIZA: Hello. How are you feeling today?");
        System.out.println("User: I am sad");
        System.out.println("ELIZA: " + respond("I am sad"));
        System.out.println("User: My mother never listens");
        System.out.println("ELIZA: " + respond("My mother never listens"));
    }
}

